#!/usr/bin/env python3
import vllm  # noqa: F401 - must import first to patch torch.cuda
import sys
import subprocess

# Pass all arguments after the script name to lm_eval
result = subprocess.run(
    [sys.executable, "-m", "lm_eval"] + sys.argv[1:],
    env={**dict(__import__("os").environ), "PYTHONPATH": ""}
)
sys.exit(result.returncode)

